// library's SearchService to query nuget.org for packages whose id starts with a prefix.

using NuGetFetch;

const string prefix = "Newtonsoft";
const string searchUrl = "https://azuresearch-usnc.nuget.org/query";

using var http = new HttpClient();
var search = new SearchService(http, searchUrl);

IReadOnlyList<SearchResult> results =
    await search.SearchByPrefixAsync(prefix, take: 100, prerelease: false, CancellationToken.None);

foreach (var result in results
             .Where(r => r.Id.StartsWith(prefix, StringComparison.OrdinalIgnoreCase))
             .OrderBy(r => r.Id, StringComparer.OrdinalIgnoreCase))
{
    Console.WriteLine($"pkg: {result.Id}");
}
"}

